diff --git a/llvm/lib/Analysis/LoopAccessAnalysis.cpp b/llvm/lib/Analysis/LoopAccessAnalysis.cpp
index cf3bb6a8eae1..7b757639cc8e 100644
--- a/llvm/lib/Analysis/LoopAccessAnalysis.cpp
+++ b/llvm/lib/Analysis/LoopAccessAnalysis.cpp
@@ -539,6 +539,7 @@ void RuntimePointerChecking::groupChecks(

         // Go through all the existing sets and see if we can find one
         // which can include this pointer.
+        unsigned PtrAS = Pointers[Pointer].PointerValue->getType()->getPointerAddressSpace();
         for (RuntimeCheckingPtrGroup &Group : Groups) {
           // Don't perform more than a certain amount of comparisons.
           // This should limit the cost of grouping the pointers to something
@@ -549,6 +550,11 @@ void RuntimePointerChecking::groupChecks(

           TotalComparisons++;

+          // Skip groups with different address spaces since all pointers
+          // in a checking group must be in the same address space.
+          if (Group.AddressSpace != PtrAS)
+            continue;
+
           if (Group.addPointer(Pointer, *this)) {
             Merged = true;
             break;
@@ -1291,6 +1297,24 @@ bool AccessAnalysis::canCheckPtrAtRT(
   // use them for the runtime check. We also have to assume they could
   // overlap. In the future there should be metadata for whether address spaces
   // are disjoint.
+  // Check for address space mismatches in the same alias set, regardless of
+  // dependency set, because pointers with different address spaces cannot be
+  // meaningfully compared even if they share the same underlying object.
+  DenseMap<unsigned, unsigned> AliasSetToAddressSpace;
+  for (unsigned i = 0; i < RtCheck.Pointers.size(); ++i) {
+    unsigned AliasSetId = RtCheck.Pointers[i].AliasSetId;
+    unsigned AS = RtCheck.Pointers[i].PointerValue->getType()->getPointerAddressSpace();
+    auto It = AliasSetToAddressSpace.find(AliasSetId);
+    if (It == AliasSetToAddressSpace.end()) {
+      AliasSetToAddressSpace[AliasSetId] = AS;
+    } else if (It->second != AS) {
+      LLVM_DEBUG(
+          dbgs() << "LAA: Alias set contains pointers with different address "
+                    "spaces\n");
+      return false;
+    }
+  }
+
   unsigned NumPointers = RtCheck.Pointers.size();
   for (unsigned i = 0; i < NumPointers; ++i) {
     for (unsigned j = i + 1; j < NumPointers; ++j) {

